async (params, browser) => {
  // Open Product Hunt homepage
  await browser.open('https://www.producthunt.com')

  // Wait for products to load
  await browser.waitForSelector('[class*=\'post\'], [data-test=\'post-item\'], a[href*=\'/posts/\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract trending products
  const trending_data = await browser.evaluate(`const products = []; const items = document.querySelectorAll('[data-test="post-item"], [class*="post-item"], div[class*="styles_item"]'); if (items.length === 0) { const links = document.querySelectorAll('a[href*="/posts/"]'); const seen = new Set(); for (let i = 0; i < links.length && products.length < 20; i++) { const el = links[i]; const href = el.getAttribute('href') || ''; if (seen.has(href) || !href) continue; seen.add(href); const nameEl = el.querySelector('h3, strong, [class*="title"]'); if (!nameEl) continue; const taglineEl = el.querySelector('p, [class*="tagline"]'); const imgEl = el.querySelector('img'); products.push({ rank: products.length + 1, name: nameEl.textContent.trim(), tagline: taglineEl ? taglineEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: href.startsWith('http') ? href : 'https://www.producthunt.com' + href }); } } else { for (let i = 0; i < Math.min(items.length, 20); i++) { const el = items[i]; const nameEl = el.querySelector('h3, strong, [class*="title"], [data-test="post-name"]'); const taglineEl = el.querySelector('p, [class*="tagline"], [data-test="post-tagline"]'); const upvotesEl = el.querySelector('[class*="vote"] span, button[class*="vote"] span'); const commentsEl = el.querySelector('[class*="comment"] span'); const linkEl = el.querySelector('a[href*="/posts/"]'); const imgEl = el.querySelector('img[src*="ph-files"], img'); products.push({ rank: i + 1, name: nameEl ? nameEl.textContent.trim() : '', tagline: taglineEl ? taglineEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', comments: commentsEl ? commentsEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); } } return { trending_count: products.length, products: products, url: window.location.href }`)

  return trending_data
}
